// Split feedback text into individual items
const courseTitle = $input.first().json['Course Title'];
const rawFeedback = $input.first().json['Feedback Responses'];
const focusArea = $input.first().json['What would you like to improve?'];

// Split by newlines, trim, remove empty lines
const lines = rawFeedback
  .split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0);

// Return each line as a separate item — n8n will process each one
return lines.map((line, index) => ({
  json: {
    id: index + 1,
    feedback: line,
    courseTitle,
    focusArea,
    totalResponses: lines.length
  }
}));

// Aggregate all classified responses into one summary object
const items = $input.all();
const courseTitle = $('Feedback Input Form').first().json['Course Title'];
const focusArea = $('Feedback Input Form').first().json['What would you like to improve?'];

// Parse the AI output — each item has .json.output as a JSON string
const classified = items.map(item => {
  try {
    // Try to parse the AI output as JSON
    let text = item.json.output || '';
    // Remove markdown code fences if present
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    return JSON.parse(text);
  } catch (e) {
    return {
      id: '?',
      feedback: item.json.output || 'Parse error',
      sentiment: 'unknown',
      theme: 'general',
      actionable: false,
      suggested_action: null
    };
  }
});

// Count sentiments
const sentiments = { positive: 0, negative: 0, neutral: 0, unknown: 0 };
classified.forEach(c => { sentiments[c.sentiment] = (sentiments[c.sentiment] || 0) + 1; });

// Count themes
const themes = {};
classified.forEach(c => { themes[c.theme] = (themes[c.theme] || 0) + 1; });

// Collect actionable items
const actionableItems = classified
  .filter(c => c.actionable)
  .map(c => ({ feedback: c.feedback, action: c.suggested_action, theme: c.theme }));

return [{
  json: {
    courseTitle,
    focusArea,
    totalResponses: classified.length,
    sentiments,
    themes,
    actionableItems,
    allClassified: classified
  }
}];

